import{_ as e,o as a,c as i,e as r}from"./app.50ad9e00.js";const h={},l=r('<h1 id="使用条款" tabindex="-1"><a class="header-anchor" href="#使用条款" aria-hidden="true">#</a> 使用条款</h1><p>感谢您使用ToMemo，您的支持让我们更有动力去完善这个产品。</p><h2 id="定价策略" tabindex="-1"><a class="header-anchor" href="#定价策略" aria-hidden="true">#</a> 定价策略</h2><p>ToMemo基础版无需付费，在功能的使用上有限制。</p><p>ToMemo进阶版需要付费，购买进阶版本之后您可以无限制使用全部功能。付费方案是终身买断制 + 订阅制。</p><ul><li>买断制：您只需要付费一次，即可永久使用。</li><li>订阅制：按月订阅方便试用所有功能；按年订阅是对我们最大的支持。</li></ul><h3 id="价格" tabindex="-1"><a class="header-anchor" href="#价格" aria-hidden="true">#</a> 价格</h3><ul><li>买断进阶版： 12元</li><li>按月订阅：2元</li><li>按年订阅：12元</li></ul><div class="custom-container danger"><p class="custom-container-title">DANGER</p><ul><li>购买后的记录与App Store中的账号绑定，切换账号会重新确认进阶版购买凭证，建议使用商店中最常用的账号购买。</li><li>因为之前配置不熟悉，导致上架了「高级版」和「进阶版」，这两个是一个版本，解锁的内容也是一样的，请放心购买。</li></ul></div><h2 id="退款" tabindex="-1"><a class="header-anchor" href="#退款" aria-hidden="true">#</a> 退款</h2><p>如果您有这样的想法，我们感到很遗憾，所以请优先考虑通过联系我们来解决您不满的地方，但我们始终尊重您的选择。</p><p>然而，应用的退款流程并不受开发者掌控，所以我们建议您联系 Apple 的支持团队来处理退款，您可以在这里找到相关信息。</p><h2 id="本隐使用条款的变更" tabindex="-1"><a class="header-anchor" href="#本隐使用条款的变更" aria-hidden="true">#</a> 本隐使用条款的变更</h2><p>我们可能会不时地更新我们的使用条款以适应ToMemo最新的情况。因此，我们建议您定期查看本页面以了解最新的内容。</p><p>我们将通过在此页面上发布新的使用条款来通知您任何更改。所有更改在此页面上发布后立即生效。</p><h2 id="联系我们" tabindex="-1"><a class="header-anchor" href="#联系我们" aria-hidden="true">#</a> 联系我们</h2><p>如果您对我们的使用条款有任何疑问或建议，请通过 <a href="mailto:hi@leozhou.me">hi@leozhou.me</a> 与我们联系。</p>',17),t=[l];function d(o,n){return a(),i("div",null,t)}const s=e(h,[["render",d],["__file","terms.html.vue"]]);export{s as default};
